SELECT division_id, SUM(total_expense) AS total_division_expense
FROM expense_details
WHERE division_id = 1;

SELECT total_expense
FROM expense_details
WHERE expense_id = 1;

SELECT SUM(total_expense) AS total_expenses
FROM expense_details
WHERE division_id = 1;

SELECT total_expense
FROM expense_details
WHERE division_id = 1 AND category_id = 0;

SELECT expense_id, total_expense
FROM expense_details
ORDER BY total_expense DESC;

SELECT category_name
FROM expense_categories
WHERE category_id = 1;
